background:#0f4da2;    color:#fff;    font-weight:700;}.compact-table tr:nth-child(even) {    background:#f9fbff;}.table-title {    background:#0f4da2;    color:#fff;    font-size:15px;    padding:8px;    text-align:center;}.table-subhead {    background:#eef6ff;    font-weight:600;    padding:6px;}.no-records {    padding:12px;    text-align:center;    color:#666;    font-size:14px;}@media (max-width:820px) {    .export-buttons { flex-wrap:wrap; }}</style><!-- PDF + CSV Export Script --><script src="https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js"></script><script src="https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js"></script><script>// EXPORT CSVfunction exportCSV() {    var table = document.querySelector("#pdf-area .compact-table");    if (!table) { alert("No table to export"); return; }    var rows = [];    // header    table.querySelectorAll("thead tr").forEach(function(tr) {        var row = [];        tr.querySelectorAll("th").forEach(function(th) { row.push(th.innerText.trim()); });        rows.push(row);    });    // body    table.querySelectorAll("tbody tr").forEach(function(tr) {        var row = [];        tr.querySelectorAll("td").forEach(function(td) { row.push(td.innerText.trim()); });        rows.push(row);    });    var csv = "";    rows.forEach(function(row){ csv += row.join(",") + "\n"; });    var blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });    var link = document.createElement("a");    link.href = URL.createObjectURL(blob);    var fname = "Power_vs_Windspeed_<?= preg_replace('/[^A-Za-z0-9]/','_', ($All_Devicename[1] ?? 'device')) ?>_<?= date('Y-m-d') ?>.csv";    link.download = fname;    document.body.appendChild(link);    link.click();    document.body.removeChild(link);}// EXPORT PDF (captures the pdf-area)function exportPDF() {    const element = document.getElementById('pdf-area');    if (!element) { alert("Nothing to export"); return; }    // Use useCORS and white background for more reliable capture    html2canvas(element, { scale: 2, useCORS: true, backgroundColor: "#ffffff" }).then(canvas => {        const imgData = canvas.toDataURL("image/png");        const { jsPDF } = window.jspdf;        const pdf = new jsPDF("p", "pt", "a4");        const pageWidth = pdf.internal.pageSize.getWidth();        const pageHeight = pdf.internal.pageSize.getHeight();        const imgWidth = pageWidth - 40; // left & right margins        const imgHeight = (canvas.height * imgWidth) / canvas.width;        let position = 20;        if (imgHeight <= (pageHeight - 40)) {            pdf.addImage(imgData, "PNG", 20, position, imgWidth, imgHeight);        } else {            // multi-page            let heightLeft = imgHeight;            let y = 20;            let pageCanvas = canvas;            // Add first page            pdf.addImage(imgData, "PNG", 20, y, imgWidth, imgHeight);            heightLeft -= (pageHeight - 40);            while (heightLeft > 0) {                pdf.addPage();                // For simple approach re-use same image positioned to show next portion:                y = - (imgHeight - heightLeft) + 20;                pdf.addImage(imgData, "PNG", 20, y, imgWidth, imgHeight);                heightLeft -= (pageHeight - 40);            }        }        var fname = "Power_vs_Windspeed_<?= preg_replace('/[^A-Za-z0-9]/','_', ($All_Devicename[1] ?? 'device')) ?>_<?= date('Y-m-d') ?>.pdf";        pdf.save(fname);    }).catch(function(err){        alert("PDF export failed: " + (err && err.message ? err.message : err));    });}</script>